import React, {useEffect, useRef, useState} from 'react'
import {ReactNavbar} from "react-responsive-animate-navbar";

const Navbar = () => {
    // const didMountRef = useRef(false);
    // useEffect( () => {
    //     if (didMountRef.current) {
    //
    //         document.querySelectorAll("html body .styles_navLinks__38tON ul li")[0].addEventListener('click', e=>{
    //             window.scrollTo({
    //                 top: 400,
    //                 behavior: 'smooth',
    //             });
    //             console.log("HOME");
    //         });
    //     } else
    //     {
    //         didMountRef.current = true;
    //         console.log("HERE")
    //     }
    //
    //
    // });
    const [isHovered,SetHovered] = useState(false);
    useEffect(() => {
        const mainNavChildren = document.querySelectorAll("html body .styles_navLinks__38tON ul li a");
        const mobileNavChildren = document.querySelectorAll("html body .MobileNav_MoNavLinks__mNUdF ul li a")
        if(isHovered
            && typeof(mainNavChildren) !== 'undefined' && mainNavChildren.length)
        {
            let childId = ['topElement','aboutme','project','project'];
            let index = 0;
            childId.forEach((id)=>{
                if(index===0)
                {
                    mainNavChildren[index].addEventListener('click', (e) => {

                            window.scrollTo({
                                top: 0,
                                behavior: 'smooth',
                            });

                        }

                    );
                } else
                {
                    mainNavChildren[index].addEventListener('click', (e) => {

                            window.scrollTo({
                                top: document.getElementById(id).getBoundingClientRect().top +  window.pageYOffset - 55,
                                behavior: 'smooth',
                            });

                        }

                    );
                }
                index++;


            });
            // mainNavChildren.forEach((child)=>{
            //
            //     child.addEventListener('click', (e) => {
            //         window.scrollTo({
            //             top: 0,
            //             behavior: 'smooth',
            //         });
            //
            //     });
            // });
            // mainNavChildren[0].addEventListener('click', (e) => {
            //
            //         window.scrollTo({
            //             top: 0,
            //             behavior: 'smooth',
            //         });
            //
            //     }
            //
            // );
            // let aboutme = 'aboutme';
            // mainNavChildren[1].addEventListener('click', (e) => {
            //
            //         window.scrollTo({
            //             top: document.getElementById(aboutme).getBoundingClientRect().top +  window.pageYOffset - 55,
            //             behavior: 'smooth',
            //         });
            //
            //     }
            //
            // );
            // mainNavChildren[2].addEventListener('click', (e) => {
            //
            //         window.scrollTo({
            //             top: document.getElementById('project').getBoundingClientRect().top +  window.pageYOffset - 55,
            //             behavior: 'smooth',
            //         });
            //
            //     }
            //
            // );
            // mainNavChildren[3].addEventListener('click', (e) => {
            //
            //         window.scrollTo({
            //             top: document.getElementById('project').getBoundingClientRect().top +  window.pageYOffset - 55,
            //             behavior: 'smooth',
            //         });
            //
            //     }
            //
            // );
        }
        if(isHovered
            && typeof(mobileNavChildren) !== 'undefined' && mobileNavChildren.length)
        {
            mobileNavChildren[0].addEventListener('click', (e) => {

                    window.scrollTo({
                        top: 0,
                        behavior: 'smooth',
                    });

                }

            );
            mobileNavChildren[1].addEventListener('click', (e) => {

                    window.scrollTo({
                        top: document.getElementById('aboutme').getBoundingClientRect().top +  window.pageYOffset - 55,
                        behavior: 'smooth',
                    });

                }

            );
            mobileNavChildren[2].addEventListener('click', (e) => {

                    window.scrollTo({
                        top: document.getElementById('project').getBoundingClientRect().top +  window.pageYOffset - 55,
                        behavior: 'smooth',
                    });

                }

            );
            mobileNavChildren[3].addEventListener('click', (e) => {

                    window.scrollTo({
                        top: document.getElementById('project').getBoundingClientRect().top +  window.pageYOffset - 55,
                        behavior: 'smooth',
                    });

                }

            );
        }

    });
    return (
        <div
            onMouseEnter={()=>SetHovered(true)}
            onMouseLeave={()=>SetHovered(false)}
        >
        <ReactNavbar
            color="rgb(25,100,50)"
            logo='logo-removebg-preview.png'

            menu={[
                { name: "HOME", to: "/" },
                { name: "ABOUT ME", to: "aboutme" },
                { name: "PROJECT", to: "project" },
                { name: "CONTACT", to: "contact" },
            ]}
            social={[
                {
                    name: "Linkedin",
                    url: "https://www.linkedin.com/in/daniel-lee-00991085",
                    icon: ["fab", "linkedin-in"],
                },
                {
                    name: "Github",
                    url: "https://github.com/DMZnoo",
                    icon: ["fab", "github"],
                }
            ]}

        />
        </div>
    )
};
export default Navbar;
